import{_ as l,c as e,o as i,aP as a}from"./chunks/framework.BQ2N21Ks.js";const g=JSON.parse('{"title":"曾楚龙 - 全栈工程师","titleTemplate":"个人简历","description":"","frontmatter":{"titleTemplate":"个人简历"},"headers":[],"relativePath":"intro/index.md","filePath":"intro/index.md","lastUpdated":1713692574000}'),t={name:"intro/index.md"},r=a('<h1 id="曾楚龙-全栈工程师" tabindex="-1">曾楚龙 - 全栈工程师 <a class="header-anchor" href="#曾楚龙-全栈工程师" aria-label="Permalink to &quot;曾楚龙 - 全栈工程师&quot;">​</a></h1><p>博客 👉 <a href="https://blog.hisher.site" target="_blank" rel="noreferrer">https://blog.hisher.site</a></p><p>GitHub 👉 <a href="https://github.com/ClungTsang" target="_blank" rel="noreferrer">https://github.com/ClungTsang</a></p><p>掘金 👉 <a href="https://juejin.cn/user/289926802319896" target="_blank" rel="noreferrer">https://juejin.cn/user/289926802319896</a></p><p>邮箱 📥 <a href="mailto:shawn1440982358@163.com" target="_blank" rel="noreferrer">shawn1440982358@163.com</a></p><p>电话 📱 18680271761</p><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><ul><li>于2020年开始承接项目，具备独立负责技术选型、需求定制开发、服务器选型、域名购买、部署和上线工作。</li><li>4年前端经验：Vue2全家桶、Vue3全家桶、Nuxt3、Uniapp、支付宝微信抖音原生小程序、后台管理系统、PC官网、独立站</li><li>2年后端经验：Java、SpringBoot、MyBatisPlus</li><li>具备全栈开发的能力</li><li>大学期间获得省、国家级各类奖项若干（包含第八届大学生软件杯全国一等奖）</li></ul><h2 id="工作" tabindex="-1">工作 <a class="header-anchor" href="#工作" aria-label="Permalink to &quot;工作&quot;">​</a></h2><h3 id="深圳金都源科技有限公司-全栈开发工程师" tabindex="-1">深圳金都源科技有限公司 --- 全栈开发工程师 <a class="header-anchor" href="#深圳金都源科技有限公司-全栈开发工程师" aria-label="Permalink to &quot;深圳金都源科技有限公司 --- 全栈开发工程师&quot;">​</a></h3><blockquote><p><strong>云汇租机</strong> 是一款可以自由租赁手机产品的支付宝小程序<br> 技术栈：SpringBoot、MyBatisPlus、Docker、Vue3全家桶、TS</p></blockquote><ul><li>开发项目 <ul><li>支付宝小程序（Uniapp、uView）</li><li>前台管理系统（Vue3、TS、view-design）</li><li>后端（SpringBoot、MyBatisPlus）</li></ul></li><li>主要业绩 <ul><li>根据UV和实际业务需求实现弹性伸缩，降低 <strong>30%</strong> 的服务器成本。</li></ul></li></ul><h3 id="深圳领辰世纪科技有限公司-前端开发工程师" tabindex="-1">深圳领辰世纪科技有限公司 --- 前端开发工程师 <a class="header-anchor" href="#深圳领辰世纪科技有限公司-前端开发工程师" aria-label="Permalink to &quot;深圳领辰世纪科技有限公司 --- 前端开发工程师&quot;">​</a></h3><blockquote><p><strong>领辰移民</strong> 是一款全方位移民留学服务平台，采用最新最稳最美观的开发框架<br> 技术栈：Nuxt3、SEO、Vue3全家桶、Uniapp、ElementPlus、Animation、PM2进程守护、TailwindCSS、百度数据统计、高德地图、客服系统</p></blockquote><ul><li>开发项目 <ul><li><a href="https://lc.plus" target="_blank" rel="noreferrer">官网网站</a>（Nuxt3，SEO，SSR）</li><li><a href="https://m.lc.plus" target="_blank" rel="noreferrer">移动端程序</a>（vue2）</li><li>CRM管理系统（ElementPlus ，vue3）</li></ul></li><li>主要业绩 <ul><li>使用预渲染技术生成静态页面，同时配配置服务端压缩，使首次访问页面的加载体积减少 <strong>50%</strong>，加载耗时减少 <strong>30%</strong>。</li><li>针对客服和地图等组件，实现客户端按需加载，极大丰富了网站的使用场景。</li><li>配置nginx文件，根据访问端的设备信息跳转对应的网站，提高了用户访问体验。</li><li>公司简介中添加动画加载效果，提升公司形象气质。</li></ul></li></ul><h3 id="深圳冠洲信息科技有限公司-前端开发工程师" tabindex="-1">深圳冠洲信息科技有限公司 --- 前端开发工程师 <a class="header-anchor" href="#深圳冠洲信息科技有限公司-前端开发工程师" aria-label="Permalink to &quot;深圳冠洲信息科技有限公司 --- 前端开发工程师&quot;">​</a></h3><blockquote><p><strong>象小美租手机</strong> ，是一款可以自由租赁3c电子产品的支付宝小程序 技术栈：小程序原生、vue2全家桶、ElementUi、友盟数据统计</p></blockquote><ul><li>开发项目 <ul><li>支付宝小程序（原生）</li><li>ERP后台管理系统（ElementUi ，vue2）</li></ul></li><li>主要业绩 <ul><li>支付宝原生语言开发，同时采用分包加载、极大提高兼容性和流畅度。</li><li>首页采用按需加载方案，并且通过缓存和异步刷新的技术，提高代码质量，从而获得支付宝流量扶持。</li><li>将普通后台系统 <strong>重构成</strong> ERP权限管理系统</li></ul></li></ul><h2 id="技能" tabindex="-1">技能 <a class="header-anchor" href="#技能" aria-label="Permalink to &quot;技能&quot;">​</a></h2><h3 id="前端开发" tabindex="-1">前端开发 <a class="header-anchor" href="#前端开发" aria-label="Permalink to &quot;前端开发&quot;">​</a></h3><ul><li>掌握vue2、3全家桶、uni-app的响应式布局和移动端开发</li><li>掌握官网、后台、微信（包括支付宝，抖音）小程序开发</li><li>了解js底层原理，vue底层原理</li><li>敏捷开发 <ul><li>调用自己封装的轮子和Hooks函数</li><li>基于TailwindCSS，UnoCSS快速生成网页</li><li>熟练掌握运用ES6语法</li></ul></li></ul><h3 id="负责项目的生命周期" tabindex="-1">负责项目的生命周期 <a class="header-anchor" href="#负责项目的生命周期" aria-label="Permalink to &quot;负责项目的生命周期&quot;">​</a></h3><ul><li>0-1全流程开发和上线 <ul><li>选配、购买、配置服务器、ssl证书、域名解析</li><li>git仓库搭建、ssh密钥配置、git分支管理、git提交命名规范</li><li>项目技术选型、框架搭建、readme.md、技术和操作文档编写</li><li>项目打包、压缩、SSG静态运行、pm2守护进程运行、SEO搜索引擎优化、nginx反向代理</li></ul></li></ul><h3 id="英语能力" tabindex="-1">英语能力 <a class="header-anchor" href="#英语能力" aria-label="Permalink to &quot;英语能力&quot;">​</a></h3><ul><li>英语阅读、口语、交流、对接</li><li>全英文官方源码、规范命名</li></ul><h3 id="能力拓展" tabindex="-1">能力拓展 <a class="header-anchor" href="#能力拓展" aria-label="Permalink to &quot;能力拓展&quot;">​</a></h3><ul><li>便于个人积累，我开发基于vitepress的<a href="https://blog.hisher.site" target="_blank" rel="noreferrer">个人博客</a>，将其部署在我的个人服务器上</li><li>通过网站托管平台生成我的<a href="https://clung-tsang-github-io.vercel.app/" target="_blank" rel="noreferrer">Vercel博客站点</a>和<a href="https://clungtsang.github.io/" target="_blank" rel="noreferrer">Github个人站点</a></li></ul>',27),n=[r];function o(s,u,h,c,p,d){return i(),e("div",null,n)}const f=l(t,[["render",o]]);export{g as __pageData,f as default};
